describe('EmailChannelHandler', () => {
  let eventBus: EventBus;
  let emailHandler: EmailChannelHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    emailHandler = new EmailChannelHandler(eventBus);
    resetNotificationIdCounter();
  });

  it('should deliver email notifications from EventBus', async () => {
    const event: NotificationRequestedEvent = {
      type: 'notification:requested',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Welcome',
      body: 'Welcome to TaskFlow Pro!',
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const delivered = emailHandler.getDeliveredEmails();
    expect(delivered).toHaveLength(1);
    expect(delivered[0]?.channel).toBe('email');
    expect(delivered[0]?.recipient).toBe('alice@example.com');
    expect(delivered[0]?.subject).toBe('Welcome');
    expect(delivered[0]?.body).toBe('Welcome to TaskFlow Pro!');
  });

  it('should ignore non-email channel notifications', async () => {
    const event: NotificationRequestedEvent = {
      type: 'notification:requested',
      channel: 'sms',
      recipient: '+1234567890',
      subject: 'SMS Test',
      body: 'This should not be delivered by email handler',
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(emailHandler.getDeliveredCount()).toBe(0);
  });

  it('should track delivered count', async () => {
    for (let i = 0; i < 3; i++) {
      await eventBus.emit<NotificationRequestedEvent>({
        type: 'notification:requested',
        channel: 'email',
        recipient: `user${i}@example.com`,
        subject: `Email ${i}`,
        body: `Body ${i}`,
        timestamp: new Date(),
      });
    }

    expect(emailHandler.getDeliveredCount()).toBe(3);
  });

  it('should clear delivered emails', async () => {
    await eventBus.emit<NotificationRequestedEvent>({
      type: 'notification:requested',
      channel: 'email',
      recipient: 'test@example.com',
      subject: 'Test',
      body: 'Test body',
      timestamp: new Date(),
    });

    emailHandler.clearDelivered();
    expect(emailHandler.getDeliveredCount()).toBe(0);
  });

  it('should work end-to-end with NotificationService', async () => {
    statusChangeCallbacks.clear();
    const service = new NotificationService(eventBus);

    service.dispatchNotification({
      recipient: 'dave@example.com',
      subject: 'End-to-End Test',
      body: 'This flows through the full pipeline',
    });

    const delivered = emailHandler.getDeliveredEmails();
    expect(delivered).toHaveLength(1);
    expect(delivered[0]?.recipient).toBe('dave@example.com');
    expect(delivered[0]?.subject).toBe('End-to-End Test');
  });
});
